class SVGParser(HTMLParser):
    def __init__(self):
        super().__init__()
        self.rects = []
        self.group_stack = []

    def handle_starttag(self, tag, attrs):
        attrs_dict = dict(attrs)
        if tag == 'g':
            self.group_stack.append(attrs_dict)
        elif tag == 'rect':
            self.rects.append({
                'rect_attrs': attrs_dict,
                'parent_groups': list(self.group_stack)
            })

    def handle_endtag(self, tag):
        if tag == 'g' and self.group_stack:
            self.group_stack.pop()

