from html.parser import HTMLParser

class ChildParser(HTMLParser):
    def __init__(self):
        super().__init__()
        self.in_mark_rect = False
        self.depth = 0
        self.children = []

    def handle_starttag(self, tag, attrs):
        attrs_dict = dict(attrs)
        cls = attrs_dict.get('class', '')
        if 'mark-rect' in cls:
            self.in_mark_rect = True
            self.depth = 0
        if self.in_mark_rect:
            self.depth += 1
            self.children.append((tag, attrs_dict))

    def handle_endtag(self, tag):
        if self.in_mark_rect:
            self.depth -= 1
            if self.depth == 0:
                self.in_mark_rect = False

parser = ChildParser()
parser.feed(content)
print(f'Total children: {len(parser.children)}')
for i, child in enumerate(parser.children[:20]):
